.intravox-header h1[data-v-7ba5bd90] {
    font-size: 18px;
}
.intravox-nav-bar[data-v-7ba5bd90] {
    width: 100%;
    box-sizing: border-box;
}
.intravox-content[data-v-7ba5bd90] {
    padding: 8px;
    padding-bottom: 40px;
    max-width: 100%;
    width: 100%;
    box-sizing: border-box;
}
.page-title-input[data-v-7ba5bd90] {
    min-width: 0;
    width: 100%;
    max-width: 250px;
    font-size: 18px;
}
.header-right[data-v-7ba5bd90] {
    gap: 4px;
}
}
