.footer-content-and-actions[data-v-40ab164b] {
    flex-direction: column;
    gap: 12px;
}
.footer-actions[data-v-40ab164b],
  .footer-edit-actions[data-v-40ab164b] {
    width: 100%;
    justify-content: flex-start;
}
.footer-content[data-v-40ab164b] {
    padding: 12px 8px;
    font-size: 13px;
}
}
